SELECT USER_ID
  FROM STOCUSER
 WHERE GATE_CD   = #{ses.gateCd}
   AND USER_TYPE = 'O'
   AND USER_NM = #{I_USER_NM}
   AND EMAIL = #{I_EMAIL}
   AND REPLACE(CELL_NUM, '-', '') = REPLACE(#{I_CELL_NO}, '-', '')

SELECT USER_ID
  FROM STOCCVUR
 WHERE GATE_CD   = #{ses.gateCd}
   AND USER_TYPE = 'S'
   AND USER_NM = #{I_USER_NM}
   AND EMAIL = #{I_EMAIL}
   AND REPLACE(CELL_NUM, '-', '') = REPLACE(#{I_CELL_NO}, '-', '')

SELECT USER_ID
  FROM STOCCVUR
 WHERE GATE_CD   = #{ses.gateCd}
   AND USER_TYPE = 'B'
   AND USER_NM = #{I_USER_NM}
   AND EMAIL = #{I_EMAIL}
   AND REPLACE(CELL_NUM, '-', '') = REPLACE(#{I_CELL_NO}, '-', '')
